
function ContactUs() {
    return (
        <>
            <section >
                <div className="container pt-5 pb-5">
                    <div className="row">
                        <div className="col-md-6">
                            <h6>Our Team</h6>
                            <p>Our team is always ready to assist you with inquiries, collaborations, and opportunities. Whether you are a model looking to grow your career or a brand searching for the right talent, we are here to guide you through every step. Feel free to reach out to us, and our team will respond as soon as possible to help you connect with the right people and opportunities.</p>
                            <br />
                            <h6>Our Office</h6>
                            <div className="d-flex">
                                <span className="fa-solid fa-location-dot me-2"></span>
                                <p>&nbsp;70 Washington Square South New York, NY 10012, United States</p>
                            </div>
                            <div className="d-flex">
                                <span className="fa-regular fa-envelope me-2"></span>
                                <p>&nbsp;contact_info@themesstrade.com</p>
                            </div>
                            <div className="d-flex">
                                <span className="fa-solid fa-phone me-2"></span>
                                <p>&nbsp;+91 000 0000 0000</p>
                            </div>
                        </div>
                        <div className="col-md-6 ">
                            <form>
                                <input type="text" className="form-control mb-3" placeholder="Your Name" />
                                <input type="email" className="form-control mb-3" placeholder="Your Email" />
                                <input type="text" className="form-control mb-3" placeholder="Subject" />
                                <textarea className="form-control mb-3" rows="5" placeholder="Message"></textarea>
                                <button type="button" className='btn commn-btn' onClick={() => alert("Message Send Successfully")}>Send Message</button>
                            </form>
                        </div>
                    </div>
                </div>
            </section >
        </>
    )
}

export default ContactUs;